const d = $input.first().json.body;

// Detectar si es edición (tiene id válido) o alta nueva.
// Saneamos: descartamos strings 'undefined'/'null'/'' que podrían llegar si
// un cliente sin validación envía el id como String(undefined) — sin esto,
// Supabase devuelve "invalid input syntax for type uuid: 'undefined'".
const rawId = d.id;
const cleanId = (rawId == null || rawId === 'undefined' || rawId === 'null' || String(rawId).trim() === '') ? null : rawId;
const isEdit = !!cleanId;

const row = {};

// Si es edición, incluir el id
if (isEdit) row.id = cleanId;

// Mapear campos del formulario → columnas de la BD
row.comercial = d['Comercial'] || '';
row.denominacion = d['Nombre Sociedad'] || d['Denominación Social'] || '';
row.nombre_comercial = d['Nombre Comercial'] || '';
row.calle = d['Calle'] || '';
row.numero = d['Número'] || '';
row.cp = d['CP'] || null;
row.municipio = d['Municipio'] || '';
row.provincia = d['Provincia'] || '';
row.cif = d['CIF/NIF'] || '';
row.email = d['Email'] || '';
row.email_factura = d['Email Factura'] || '';
row.email_cc = d['Email CC'] || '';
row.iban = d['IBAN'] || '';
row.tipo_cliente = d['Tipo Cliente'] || null;

// Firmas
row.firmas_contratadas = d['Firmas Contratadas'] || '';

// JP
row.jp_nombre = d['JP Nombre'] || '';
row.jp_apellidos = d['JP Apellidos'] || '';
row.jp_rol = d['JP Rol'] || '';
row.jp_telefono = d['JP Teléfono'] || '';
row.jp_mail = d['JP Mail'] || '';

// Firmante
row.firm_nombre = d['Firmante Nombre'] || '';
row.firm_apellidos = d['Firmante Apellidos'] || '';
row.firm_mail = d['Firmante Mail'] || '';
row.firm_dni = d['Firmante DNI'] || '';
row.firm_puesto = d['Firmante Puesto'] || '';

// TPV
row.tpv = d['TPV'] || '';
row.tpv_contacto = d['TPV Contacto'] || '';
row.tpv_email = d['TPV Email'] || '';
row.tpv_no_integrado = d['TPV No Integrado'] === 'Sí';
row.tpv_ni_nombre = d['TPV NI Nombre'] || '';
row.tpv_ni_contacto = d['TPV NI Contacto'] || '';
row.tpv_ni_email = d['TPV NI Email'] || '';

// Lite
row.lite = (d['Lite'] === 'Sí');

// Entrega
row.entrega_calle = d['Entrega Calle'] || '';
row.entrega_numero = d['Entrega Número'] || '';
row.entrega_cp = d['Entrega CP'] || null;
row.entrega_municipio = d['Entrega Municipio'] || '';
row.entrega_provincia = d['Entrega Provincia'] || '';

// Contacto
row.contacto_nombre = d['Contacto Nombre'] || '';
row.contacto_email = d['Contacto Email'] || '';
row.contacto_telefono = d['Contacto Teléfono'] || '';

// Distribuidor
row.distribuidor = (d['Distribuidor'] === 'Sí');
row.dist_empresa = d['Dist. Empresa'] || '';
row.dist_cif = d['Dist. CIF'] || '';
row.dist_direccion = d['Dist. Dirección'] || '';
row.dist_cp = d['Dist. CP'] || '';
row.dist_contacto = d['Dist. Contacto'] || '';
row.dist_mail = d['Dist. Mail'] || '';
row.dist_telefono = d['Dist. Teléfono'] || '';
row.dist_comision = parseFloat(d['Dist. Comisión Implementación (%)']) || 0;

// Financiero
row.importe_setup = parseFloat(d['ImporteSetup']) || 0;
row.descuento_setup = parseFloat(d['Descuentosetup']) || 0;
row.mensualidad_total_locales = parseFloat(d['Mensualidad Total Locales']) || 0;
row.mensualidad_total = parseFloat(d['Mensualidad Total Locales']) || 0;
row.fin_implementacion = parseFloat(d['Proyecto de Implementación']) || 0;
row.fin_basic = parseFloat(d['Plan Producto BASIC']) || 0;
row.fin_pro = parseFloat(d['Plan Producto PRO']) || 0;
row.fin_rrhh = parseFloat(d['Plan RRHH']) || 0;
row.fin_operaciones = parseFloat(d['Plan Operaciones']) || 0;
row.fin_lite = parseFloat(d['Yurest Lite']) || 0;
row.fin_integraciones = parseFloat(d['Integraciones']) || 0;
row.fin_mensualidad_anual = parseFloat(d['Mensualidad Anualizada']) || 0;

// Snapshot completo del carrito (items, descuentos, periodos, locales por
// módulo y precios mensuales por local). Se persiste como JSONB para poder
// reconstruir el estado exacto al editar la ficha.
if (d.paquetes_carrito !== undefined) {
  row.paquetes_carrito = d.paquetes_carrito;
}

// Credenciales
row.cred_master = d['Credencial Master'] || '';
row.cred_yurest = d['Credencial Yurest'] || '';

// Otros
row.comentarios = d['Comentarios'] || '';
row.modulos = d['Módulos'] || [];
row.baja = d['Baja'] || 'No';

// Adjuntos: PDF / JPG / PNG en base64 (JSONB). Solo se actualiza si vienen
// explícitos para no borrar accidentalmente al guardar campos sin tocarlos.
if (Array.isArray(d['Adjuntos'])) row.adjuntos = JSON.stringify(d['Adjuntos']);
else if (Array.isArray(d.adjuntos)) row.adjuntos = JSON.stringify(d.adjuntos);

// Estado (si viene en el payload)
if (d['Estado']) row.estado = String(d['Estado']).toLowerCase();

// Locales se procesarán aparte
const locales = d.locales || [];

return [{ json: { row, locales, isEdit } }];

// UPDATE: extraer row para actualizar
const { row } = $input.first().json;
return [{ json: row }];

// INSERT: extraer row sin id
const { row } = $input.first().json;
delete row.id;
return [{ json: row }];

// Procesar locales: obtener ficha_id del resultado del insert/update
const fichaResult = $input.first().json;
const fichaId = fichaResult.id;

// Recuperar locales del nodo anterior
const prepareNode = $('Preparar Ficha').first().json;
const locales = prepareNode.locales || [];
const isEdit = prepareNode.isEdit;

if (locales.length === 0) {
  return [{ json: { fichaId, success: true, localesCount: 0 } }];
}

// Preparar locales para insertar
const rows = locales.map(l => ({
  ficha_id: fichaId,
  nombre: l.nombre || '',
  email: l.email || '',
  calle: l.calle || '',
  numero: l.numero || '',
  cp: l.cp || '',
  sociedad_cif: l.sociedad_cif || '',
  sociedad_denominacion: l.sociedad_denominacion || '',
  sociedad_calle: l.sociedad_calle || '',
  sociedad_numero: l.sociedad_numero || '',
  sociedad_cp: l.sociedad_cp || '',
  sociedad_municipio: l.sociedad_municipio || '',
  sociedad_provincia: l.sociedad_provincia || '',
  mensualidad: parseFloat(l.mensualidad) || 0
}));

return rows.map(r => ({ json: r }));
